/**
 * Get a translated UI string.
 * Keys are the English display text (e.g., "Back to", "Overview").
 */
export function t(key: string, lang: string): string {
  const entry = UI[key];
  if (!entry) return key;
  return entry[lang] || entry.eng || key;
}
